const GRAMMAR = [
  // ===== Te-form Patterns =====
  { id: "g001", pattern: "〜ている", meaning: "ongoing action; resultant state", usage: "Shows an action currently in progress, or a state that results from a completed action (e.g. the door is open).", example: "彼女は今、電話をしています。", exampleEn: "She is on the phone right now.", category: "te-form", level: "basic" },
  { id: "g002", pattern: "〜てある", meaning: "resultant state (deliberately done)", usage: "Something has been done intentionally and the result remains. Implies preparation by someone.", example: "黒板に時間割が書いてあります。", exampleEn: "The timetable is written on the blackboard.", category: "te-form", level: "basic" },
  { id: "g003", pattern: "〜ておく", meaning: "do in advance; leave as is", usage: "Do something ahead of time in preparation, or leave something in a state intentionally.", example: "明日の会議のために資料を準備しておきます。", exampleEn: "I'll prepare the materials in advance for tomorrow's meeting.", category: "te-form", level: "intermediate" },
  { id: "g004", pattern: "〜てしまう", meaning: "completion; done (often with regret)", usage: "Expresses completion of an action, often unintentional or regrettable. Casual form: 〜ちゃう.", example: "財布を忘れてしまいました。", exampleEn: "I went and forgot my wallet.", category: "te-form", level: "intermediate" },
  { id: "g005", pattern: "〜てくる", meaning: "action toward speaker; gradual change starting", usage: "Action directed toward the present moment, or a change that began in the past and continues now.", example: "コーヒーを買ってきます。", exampleEn: "I'll go buy coffee and come back.", category: "te-form", level: "intermediate" },
  { id: "g006", pattern: "〜ていく", meaning: "action away from speaker; continuing change", usage: "Action or change moving away from the present into the future.", example: "日本語がだんだん上手になっていきます。", exampleEn: "My Japanese is gradually getting better.", category: "te-form", level: "intermediate" },
  { id: "g007", pattern: "〜てみる", meaning: "try doing; do and see", usage: "Try doing something to see what it's like or what happens.", example: "この料理を食べてみてください。", exampleEn: "Please try eating this dish.", category: "te-form", level: "basic" },
  { id: "g008", pattern: "〜てほしい", meaning: "want someone else to do", usage: "Expresses desire for another person to do something. The person is marked with に.", example: "もっとゆっくり話してほしいです。", exampleEn: "I want you to speak more slowly.", category: "te-form", level: "intermediate" },
  { id: "g009", pattern: "〜てから", meaning: "after doing X, then...", usage: "One action is fully completed before the next begins.", example: "宿題をしてから、ゲームをします。", exampleEn: "After doing homework, I'll play games.", category: "te-form", level: "basic" },
  { id: "g010", pattern: "〜てもいい", meaning: "it's okay to do; may do (permission)", usage: "Grants permission to perform an action.", example: "ここで写真を撮ってもいいですか。", exampleEn: "Is it okay to take photos here?", category: "permission", level: "basic" },
  { id: "g011", pattern: "〜てはいけない", meaning: "must not do; not allowed (prohibition)", usage: "Prohibits an action. Stronger than 〜てもいい.", example: "図書館で電話をしてはいけません。", exampleEn: "You must not use the phone in the library.", category: "permission", level: "basic" },
  { id: "g012", pattern: "〜ていただけませんか", meaning: "would you please do (very polite request)", usage: "Very polite request form. More formal than 〜てください or 〜てくれませんか.", example: "もう一度説明していただけませんか。", exampleEn: "Could you please explain it one more time?", category: "te-form", level: "advanced" },

  // ===== Conditionals =====
  { id: "g013", pattern: "〜ば", meaning: "if (hypothetical/logical conditional)", usage: "Hypothetical or logical condition. The result must follow naturally. Not for past conditions.", example: "もっと練習すれば、上手になります。", exampleEn: "If you practice more, you'll get better.", category: "conditional", level: "intermediate" },
  { id: "g014", pattern: "〜たら", meaning: "if; when (conversational conditional)", usage: "Most versatile conditional. Can mean 'if' or 'when', and can be used for past or future events.", example: "駅に着いたら、電話してください。", exampleEn: "When you arrive at the station, please call me.", category: "conditional", level: "basic" },
  { id: "g015", pattern: "〜と", meaning: "when; if (natural or automatic result)", usage: "Expresses an automatic or inevitable result. Cannot be used with requests or intentions in the main clause.", example: "右に曲がると、駅があります。", exampleEn: "When you turn right, there is a station.", category: "conditional", level: "basic" },
  { id: "g016", pattern: "〜なら", meaning: "if that's the case; speaking of (contextual)", usage: "Conditional based on information provided by the other person. Often translated as 'if you're talking about' or 'if that's the case'.", example: "日本に行くなら、京都がおすすめです。", exampleEn: "If you're going to Japan, I recommend Kyoto.", category: "conditional", level: "intermediate" },

  // ===== Obligation & Necessity =====
  { id: "g017", pattern: "〜なければならない", meaning: "must do; have to do (obligation)", usage: "Formal expression of obligation or necessity. Casual short form: 〜なきゃ.", example: "明日までにレポートを書かなければなりません。", exampleEn: "I have to write the report by tomorrow.", category: "obligation", level: "basic" },
  { id: "g018", pattern: "〜なくてはいけない", meaning: "must do; have to do (slightly casual)", usage: "Expresses obligation. Slightly less formal than なければならない. Casual form: 〜なくちゃ.", example: "薬を飲まなくてはいけません。", exampleEn: "I have to take my medicine.", category: "obligation", level: "basic" },
  { id: "g019", pattern: "〜なくてもいい", meaning: "don't have to; not necessary to do", usage: "Expresses that something is not required or necessary.", example: "明日は来なくてもいいですよ。", exampleEn: "You don't have to come tomorrow.", category: "obligation", level: "basic" },
  { id: "g020", pattern: "〜ことができる", meaning: "can do; be able to do (formal ability)", usage: "Expresses ability or possibility. More formal than the potential verb form (〜られる/〜える).", example: "私は日本語を話すことができます。", exampleEn: "I am able to speak Japanese.", category: "ability", level: "basic" },

  // ===== Conjunctions & Transitions =====
  { id: "g021", pattern: "〜ながら", meaning: "while doing; simultaneously", usage: "Two actions done at the same time by the same subject. The main action is in the second clause.", example: "音楽を聴きながら、勉強します。", exampleEn: "I study while listening to music.", category: "conjunction", level: "basic" },
  { id: "g022", pattern: "〜前に", meaning: "before doing X", usage: "Indicates that one action happens before another. The first verb is in plain non-past form.", example: "寝る前に、歯を磨きます。", exampleEn: "I brush my teeth before going to bed.", category: "conjunction", level: "basic" },
  { id: "g023", pattern: "〜後で", meaning: "after doing X", usage: "Indicates that one action happens after another is fully completed.", example: "昼ごはんを食べた後で、散歩します。", exampleEn: "After eating lunch, I'll take a walk.", category: "conjunction", level: "basic" },
  { id: "g024", pattern: "〜ために", meaning: "in order to; for the purpose of; due to", usage: "Expresses purpose (in order to do X) with action verbs, or cause (because of X) with nouns.", example: "日本語を上手になるために、毎日練習します。", exampleEn: "I practice every day in order to improve my Japanese.", category: "conjunction", level: "intermediate" },
  { id: "g025", pattern: "〜ように", meaning: "so that; in order to be able to", usage: "Expresses purpose focused on a state or ability to be achieved. Also used for prayers and wishes.", example: "試験に合格できるように、一生懸命勉強します。", exampleEn: "I'll study hard so that I can pass the exam.", category: "conjunction", level: "intermediate" },
  { id: "g026", pattern: "〜のに", meaning: "even though; despite (disappointment/contrast)", usage: "Expresses contrast or unexpectedness, often with a nuance of complaint or disappointment.", example: "一生懸命勉強したのに、試験に落ちました。", exampleEn: "Even though I studied hard, I failed the exam.", category: "conjunction", level: "intermediate" },
  { id: "g027", pattern: "〜ば〜ほど", meaning: "the more X, the more Y", usage: "Expresses that as one thing increases, another increases proportionally.", example: "練習すればするほど、上手になります。", exampleEn: "The more you practice, the better you become.", category: "conjunction", level: "advanced" },
  { id: "g028", pattern: "〜について", meaning: "about; concerning; regarding", usage: "Used to indicate the topic of discussion, research, or writing.", example: "環境問題について話し合いました。", exampleEn: "We discussed environmental issues.", category: "conjunction", level: "intermediate" },
  { id: "g029", pattern: "〜に対して", meaning: "toward; against; in response to; compared with", usage: "Expresses a direction, attitude, or contrast toward a person or thing.", example: "先生の質問に対して、答えました。", exampleEn: "I answered in response to the teacher's question.", category: "conjunction", level: "advanced" },
  { id: "g030", pattern: "〜によって", meaning: "by; by means of; depending on; due to", usage: "Expresses means, cause, agent of passive, or variation depending on circumstances.", example: "この橋は有名な建築家によって設計されました。", exampleEn: "This bridge was designed by a famous architect.", category: "conjunction", level: "advanced" },

  // ===== Expressing Opinions & Speculation =====
  { id: "g031", pattern: "〜そうだ (伝聞)", meaning: "I heard that; they say that (hearsay)", usage: "Reports information heard from others. Attaches to the plain form of verbs/adjectives.", example: "明日は雨が降るそうです。", exampleEn: "I heard it will rain tomorrow.", category: "speculation", level: "intermediate" },
  { id: "g032", pattern: "〜そうだ (様子)", meaning: "looks like; seems about to (appearance)", usage: "Describes something that looks a certain way based on direct observation. Attaches to verb/adjective stem.", example: "このケーキはおいしそうです。", exampleEn: "This cake looks delicious.", category: "speculation", level: "intermediate" },
  { id: "g033", pattern: "〜らしい", meaning: "seems like; apparently (indirect evidence)", usage: "Expresses inference based on indirect evidence or hearsay. Less certain than はずだ.", example: "あの店はおいしいらしいです。", exampleEn: "Apparently that restaurant is delicious.", category: "speculation", level: "intermediate" },
  { id: "g034", pattern: "〜ようだ / 〜みたいだ", meaning: "appears to be; seems like (observation)", usage: "Expresses inference based on direct observation. みたいだ is more casual.", example: "彼は疲れているようです。", exampleEn: "He appears to be tired.", category: "speculation", level: "intermediate" },
  { id: "g035", pattern: "〜はずだ", meaning: "should be; ought to; expected to", usage: "Expresses a strong expectation based on logical reasoning or prior knowledge.", example: "彼女はもう家に着いているはずです。", exampleEn: "She should have arrived home by now.", category: "speculation", level: "intermediate" },
  { id: "g036", pattern: "〜かもしれない", meaning: "might; maybe; possibly", usage: "Expresses possibility or uncertainty. Less certain than はずだ.", example: "明日は雪が降るかもしれません。", exampleEn: "It might snow tomorrow.", category: "speculation", level: "basic" },
  { id: "g037", pattern: "〜だろう / 〜でしょう", meaning: "probably; I suppose", usage: "Expresses probability or conjecture. でしょう is polite, だろう is plain/casual.", example: "彼は知っているでしょう。", exampleEn: "He probably knows.", category: "speculation", level: "basic" },
  { id: "g038", pattern: "〜と思う", meaning: "I think that; I believe that", usage: "Expresses the speaker's opinion or belief. The speaker's own thoughts.", example: "日本語は難しいと思います。", exampleEn: "I think Japanese is difficult.", category: "speculation", level: "basic" },

  // ===== Decisions & Change =====
  { id: "g039", pattern: "〜ことにする", meaning: "decide to do; choose to do", usage: "Expresses a deliberate personal decision made by the speaker.", example: "毎日運動することにしました。", exampleEn: "I decided to exercise every day.", category: "change", level: "intermediate" },
  { id: "g040", pattern: "〜ことになる", meaning: "it has been decided; it turns out that", usage: "A decision or outcome made by external forces, not the speaker's own will.", example: "来月、東京に転勤することになりました。", exampleEn: "It has been decided that I'll transfer to Tokyo next month.", category: "change", level: "intermediate" },
  { id: "g041", pattern: "〜ことになっている", meaning: "it is supposed to; rules/customs dictate", usage: "Expresses established rules, conventions, or pre-arranged schedules.", example: "この学校では制服を着ることになっています。", exampleEn: "At this school, students are supposed to wear uniforms.", category: "change", level: "intermediate" },
  { id: "g042", pattern: "〜ようにする", meaning: "make an effort to; try to (habitual)", usage: "Expresses an ongoing conscious effort to do something as a habit.", example: "毎日野菜を食べるようにしています。", exampleEn: "I make an effort to eat vegetables every day.", category: "change", level: "intermediate" },
  { id: "g043", pattern: "〜ようになる", meaning: "come to be able to; gradually start to", usage: "Expresses a gradual change in ability or habit that has developed over time.", example: "日本に来てから、納豆が食べられるようになりました。", exampleEn: "After coming to Japan, I became able to eat natto.", category: "change", level: "intermediate" },
  { id: "g044", pattern: "〜ことがある", meaning: "there are times when; it sometimes happens", usage: "Expresses that something occasionally occurs.", example: "疲れているとき、授業中に眠ることがあります。", exampleEn: "When I'm tired, there are times I fall asleep in class.", category: "change", level: "intermediate" },
  { id: "g045", pattern: "〜たことがある", meaning: "have experience of; have done before", usage: "Expresses that one has had the experience of doing something at least once in the past.", example: "富士山に登ったことがあります。", exampleEn: "I have climbed Mt. Fuji before.", category: "change", level: "basic" },

  // ===== Passive & Causative =====
  { id: "g046", pattern: "〜られる / 〜れる (受身)", meaning: "passive: to be done to; to have X done", usage: "The subject receives the action. Used for direct passive and indirect (suffering) passive.", example: "財布を盗まれました。", exampleEn: "I had my wallet stolen.", category: "passive-causative", level: "intermediate" },
  { id: "g047", pattern: "〜させる / 〜せる (使役)", meaning: "causative: make or let someone do", usage: "The subject makes or lets someone else do the action. Context determines 'make' vs 'let'.", example: "先生は生徒に本を読ませました。", exampleEn: "The teacher made the students read the book.", category: "passive-causative", level: "intermediate" },
  { id: "g048", pattern: "〜させられる (使役受身)", meaning: "causative-passive: be forced/made to do", usage: "The subject is forced to do something against their will by someone else.", example: "毎日残業させられています。", exampleEn: "I'm being made to work overtime every day.", category: "passive-causative", level: "advanced" },
  { id: "g049", pattern: "〜てもらう / 〜ていただく", meaning: "receive the favor of; have someone do for you", usage: "The speaker receives the benefit of someone's action. いただく is humble/polite.", example: "先生に作文を直してもらいました。", exampleEn: "I had my teacher correct my essay.", category: "passive-causative", level: "intermediate" },
  { id: "g050", pattern: "〜てあげる / 〜てさしあげる", meaning: "do something for someone's benefit", usage: "The speaker does something for the benefit of another person. さしあげる is humble/polite.", example: "友達に日本語を教えてあげました。", exampleEn: "I taught Japanese to my friend.", category: "passive-causative", level: "intermediate" },

  // ===== Nominalizers & Relative Clauses =====
  { id: "g051", pattern: "普通形 ＋ 名詞 (relative clause)", meaning: "plain form + noun (noun-modifying clause)", usage: "A verb or adjective in plain form modifies a noun, like an adjective. Very common in Japanese.", example: "昨日食べたラーメンはおいしかったです。", exampleEn: "The ramen I ate yesterday was delicious.", category: "relative-clause", level: "basic" },
  { id: "g052", pattern: "〜こと (nominalizer)", meaning: "the act/fact of doing (formal)", usage: "Turns a verb phrase into a noun. Used in formal writing and fixed expressions like ことができる.", example: "毎日運動することは健康に大切です。", exampleEn: "Exercising every day is important for health.", category: "relative-clause", level: "intermediate" },
  { id: "g053", pattern: "〜の (nominalizer)", meaning: "the act of; the one that (casual)", usage: "Turns a verb phrase into a noun. More casual than こと. Also replaces a previously mentioned noun.", example: "泳ぐのが好きです。", exampleEn: "I like swimming.", category: "relative-clause", level: "basic" },
  { id: "g054", pattern: "〜という ＋ 名詞", meaning: "a [noun] called; that says; known as", usage: "Introduces or defines something by name, or quotes content. Very common in AP writing tasks.", example: "「もったいない」という言葉を知っていますか。", exampleEn: "Do you know the word called 'mottainai'?", category: "relative-clause", level: "intermediate" },
  { id: "g055", pattern: "〜とき", meaning: "when; at the time of", usage: "Expresses timing. Use non-past form for a state at the time; past form if the action was completed.", example: "子供のとき、よく川で遊びました。", exampleEn: "When I was a child, I often played in the river.", category: "relative-clause", level: "basic" },

  // ===== Keigo (Honorific Language) =====
  { id: "g056", pattern: "お / ご ＋ Stem ＋ になる", meaning: "honorific: someone esteemed does X", usage: "Elevates the subject's action to show respect. Used for teachers, customers, or superiors.", example: "先生はもうお帰りになりましたか。", exampleEn: "Has the teacher already gone home?", category: "keigo", level: "advanced" },
  { id: "g057", pattern: "お / ご ＋ Stem ＋ する", meaning: "humble: I/we humbly do X for you", usage: "Lowers the speaker's own action to show humility toward the listener or a third party.", example: "荷物をお持ちします。", exampleEn: "I will humbly carry your luggage.", category: "keigo", level: "advanced" },
  { id: "g058", pattern: "いらっしゃる", meaning: "honorific: to be; to go; to come", usage: "Honorific equivalent of いる, 行く, and 来る. Used when referring to someone of higher status.", example: "社長はただいまいらっしゃいません。", exampleEn: "The president is not in right now.", category: "keigo", level: "advanced" },
  { id: "g059", pattern: "おっしゃる", meaning: "honorific: to say", usage: "Honorific equivalent of 言う. Used when reporting what a person of higher status said.", example: "先生がおっしゃったことを覚えていますか。", exampleEn: "Do you remember what the teacher said?", category: "keigo", level: "advanced" },
  { id: "g060", pattern: "〜させていただく", meaning: "allow me to humbly do (permission + humility)", usage: "Humble expression requesting permission to do something. Very polite and common in business.", example: "では、説明させていただきます。", exampleEn: "Well then, allow me to explain.", category: "keigo", level: "advanced" },
];

// Spaced repetition: SM-2 simplified
// Each word has: easeFactor, interval, nextReview, correct, incorrect
function createInitialProgress(id) {
  return {
    id,
    easeFactor: 2.5,
    interval: 0,
    nextReview: Date.now(),
    correct: 0,
    incorrect: 0,
    lastSeen: null,
  };
}

function updateSM2(progress, quality) {
  // quality: 0-5 (0-2 = fail, 3-5 = pass)
  const p = { ...progress };
  if (quality >= 3) {
    if (p.interval === 0) p.interval = 1;
    else if (p.interval === 1) p.interval = 6;
    else p.interval = Math.round(p.interval * p.easeFactor);
    p.easeFactor = Math.max(1.3, p.easeFactor + 0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02));
    p.correct++;
  } else {
    p.interval = 0;
    p.incorrect++;
  }
  p.nextReview = Date.now() + p.interval * 24 * 60 * 60 * 1000;
  p.lastSeen = Date.now();
  return p;
}
